UPDATE room_mapping_room
SET official_permission_level = LEAST(COALESCE(official_permission_level, #{level}), #{level})
WHERE room_id = #{roomId}

UPDATE room_mapping_room
SET official_permission_level = #{level,jdbcType=INTEGER}
WHERE room_id = #{roomId}

